import * as React from 'react';
import { graphql, Link } from 'gatsby';
import { Layout } from '../context/Layout';
import { formatDate } from '~src/_utils/fortmatDate';

const NewsPage = ({ data }) => {
  const seo = {
    title: 'اخبار',
  };
  return (
    <Layout seo={seo}>
      <section className="uk-section-muted uk-section-small">
        <div className="uk-container">
          <div className="uk-grid-medium uk-child-width-1-1" data-uk-grid>
            <div className="uk-grid-medium" data-uk-grid>
              <section className="uk-width-1-1 uk-width-expand@m">
                <section className="uk-card uk-card-default uk-card-small uk-card-body tm-ignore-container">
                  <ul className="uk-list uk-list-large uk-list-divider">
                    {data.news.nodes.map(article => (
                      <div key={article.id}>
                        <li>
                          <article className="uk-article">
                            <div className="uk-article-body">
                              <div className="uk-article-meta uk-margin-xsmall-bottom">
                                <time>{formatDate(article.date)}</time>
                              </div>

                              <div>
                                <h3>
                                  <Link className="uk-link-heading" to={article.uri}>
                                    {article.title}
                                  </Link>
                                </h3>
                              </div>
                            </div>

                            <div
                              className="uk-margin-small-top"
                              dangerouslySetInnerHTML={{ __html: article.excerpt }}></div>
                          </article>
                        </li>
                      </div>
                    ))}
                  </ul>
                </section>
              </section>
              {/* 
        <aside className="uk-width-1-4 uk-visible@m tm-aside-column"></aside> */}
            </div>
          </div>
        </div>
      </section>
    </Layout>
  );
};

export default NewsPage;
export const query = graphql`
  query NewsPageQuery {
    news: allWpPost(limit: 3, filter: { categories: { nodes: { elemMatch: { id: { eq: "dGVybToyNzc=" } } } } }) {
      nodes {
        id
        title
        date
        excerpt
        uri
        featuredImage {
          node {
            localFile {
              childImageSharp {
                gatsbyImageData(layout: CONSTRAINED)
              }
            }
          }
        }
      }
    }
  }
`;
